/**
 * Generate the bundled autocomplete word list from `wordlist-english` (a MIT
 * package of SCOWL word lists split by frequency band). Run with:
 *
 *     node scripts/gen-wordlist.mjs
 *
 * SCOWL is permissively licensed (Kevin Atkinson); the notice is carried in the
 * generated file's header and in THIRD-PARTY-NOTICES. `wordlist-english` is a
 * devDependency used only here — the generated file is what ships.
 *
 * We take the common bands (10–50) of the base `english` list plus the `american`
 * spelling variants, dedupe keeping each word's LOWEST (most common) band, and emit
 * space-joined strings per band (compact; split at load). Bands 55+ are omitted —
 * they add obscure/technical words that would only noise up prose completion.
 */
import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const BANDS = [10, 20, 35, 40, 50];
const VARIANTS = ['english', 'american'];
const WORD_RE = /^[a-z]+(?:'[a-z]+)?$/; // plain lowercase words + simple contractions

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const pkgDir = path.join(root, 'node_modules', 'wordlist-english');

// word -> lowest band it appears in
const byWord = new Map();
for (const band of BANDS) {
  for (const variant of VARIANTS) {
    const file = path.join(pkgDir, `${variant}-words-${band}.json`);
    let words;
    try {
      words = JSON.parse(readFileSync(file, 'utf8'));
    } catch {
      continue; // a variant may not have every band
    }
    for (const w of words) {
      if (!WORD_RE.test(w)) continue;
      const prev = byWord.get(w);
      if (prev === undefined || band < prev) byWord.set(w, band);
    }
  }
}

// Group words by band, sorted alphabetically within each band.
const perBand = new Map(BANDS.map((b) => [b, []]));
for (const [w, b] of byWord) perBand.get(b).push(w);
for (const b of BANDS) perBand.get(b).sort();

const attribution = readFileSync(path.join(pkgDir, 'Copyright'), 'utf8')
  .split('\n')
  .slice(0, 14)
  .map((l) => ` * ${l}`.trimEnd())
  .join('\n');

const total = byWord.size;
const entries = BANDS.map((b) => `  [${b}, ${JSON.stringify(perBand.get(b).join(' '))}],`).join('\n');

const out = `/* eslint-disable */
/**
 * GENERATED by scripts/gen-wordlist.mjs — do not edit by hand.
 *
 * Common English words (${total}) from SCOWL bands ${BANDS.join('/')} (base + American
 * spellings), for source-editor autocomplete. Words are grouped by SCOWL band —
 * a lower band is a more common word, used to rank completions.
 *
 * Source data: SCOWL, via the MIT-licensed \`wordlist-english\` package.
 * SCOWL license (permissive):
${attribution}
 */
export const WORDLIST_BY_BAND: ReadonlyArray<readonly [number, string]> = [
${entries}
];
`;

const outPath = path.join(root, 'src', 'renderer', 'components', 'wordlist.generated.ts');
writeFileSync(outPath, out, 'utf8');
console.log(`wrote ${outPath}`);
console.log(`total words: ${total}`);
for (const b of BANDS) console.log(`  band ${b}: ${perBand.get(b).length}`);
const bytes = Buffer.byteLength(out, 'utf8');
console.log(`generated file: ${(bytes / 1024).toFixed(1)} KiB`);
